parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "topic": {
      "type": "string",
      "description": "Main topic or reason for the call"
    },
    "customerPhoneNumber": {
      "type": "string",
      "description": "Customer phone number - CRITICAL field"
    },
    "customerAddress": {
      "type": "string", 
      "description": "Full service address - CRITICAL field"
    },
    "customerName": {
      "type": "string",
      "description": "Customer full name"
    },
    "appointmentTime": {
      "type": "string",
      "description": "Scheduled or preferred appointment time"
    },
    "garageDoorIssues": {
      "type": "array",
      "items": {"type": "string"},
      "description": "List of garage door problems mentioned"
    },
    "keyPoints": {
      "type": "array",
      "items": {"type": "string"},
      "description": "Key discussion points"
    },
    "sentiment": {
      "type": "string",
      "description": "Customer sentiment: positive, neutral, frustrated, urgent"
    },
    "priority": {
      "type": "string",
      "description": "Priority: high, medium, low"
    },
    "category": {
      "type": "string",
      "description": "Service type: repair, installation, replacement, maintenance, emergency"
    },
    "actionItems": {
      "type": "array",
      "items": {"type": "string"},
      "description": "Follow-up actions needed"
    },
    "participants": {
      "type": "array",
      "items": {"type": "string"},
      "description": "Call participants"
    },
    "confidenceScore": {
      "type": "number",
      "description": "Data extraction confidence 0-1"
    },
    "bookingOutcome": {
      "type": "string",
      "description": "Call result: booked, callback_requested, declined, incomplete"
    },
    "callerPhoneNumber": {
      "type": "string",
      "description": "Phone number that called in (from Telnyx caller ID)"
    },
    "callDuration": {
      "type": "string",
      "description": "Length of the call if available"
    },
    "missingInfo": {
      "type": "array",
      "items": {"type": "string"},
      "description": "List of critical info that was NOT collected"
    }
  },
  "required": ["customerPhoneNumber", "customerAddress", "bookingOutcome"]
}

