parameters.jsCode:
// Get binary from Workflow Configuration node
const workflowConfig = $('Workflow Configuration1').first();
const audioFileBinary = workflowConfig.binary?.audioFile;

// Copy binary to current item
if (audioFileBinary) {
  items.forEach(item => {
    if (!item.binary) item.binary = {};
    item.binary.audioFile = audioFileBinary;
  });
}

return items;

